public static long solve(long[] nums, long k) {
    if (nums.length == 1) {
        return 0;
    }

    Arrays.sort(nums);
    long minRemove = nums.length; // Maximum possible removals

    for (int i = 0; i < nums.length; i++) {
        // Find the smallest j such that nums[j] * k >= nums[i]
        int left = i;
        int right = nums.length - 1;
        while (left < right) {
            int mid = (left + right) / 2;
            if (nums[mid] * k >= nums[i]) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        // The subarray from i to right is a candidate
        minRemove = Math.min(minRemove, nums.length - (right - i + 1));
    }

    return minRemove;
}
